    fun updateCustomerNumberRequestConfig(bankid: kotlin.String, customerid: kotlin.String, getCustomerOverviewFlatRequest: GetCustomerOverviewFlatRequest) : RequestConfig<GetCustomerOverviewFlatRequest> {
        val localVariableBody = getCustomerOverviewFlatRequest
